import json
import urllib.request
import urllib.error
import urllib.parse
from urllib.parse import urlparse

def lambda_handler(event, context):
    request = event['Records'][0]['cf']['request']
    headers = request['headers']
    
    # Define allowed domains for SSRF protection
    ALLOWED_DOMAINS = [
        'api.example.com',
        'data.example.com',
        'trusted-partner.com'
    ]
    
    # Maximum number of enrichment URLs to prevent resource exhaustion
    MAX_ENRICH_URLS = 3
    
    # Timeout for HTTP requests (in seconds)
    REQUEST_TIMEOUT = 2
    
    # Maximum response size (in bytes) - 100KB
    MAX_RESPONSE_SIZE = 102400
    
    # Check for enrichment URL headers
    enrich_urls = []
    for header_name in headers:
        if header_name.startswith('x-enrich-url'):
            for header_value in headers[header_name]:
                enrich_urls.append(header_value['value'])
    
    # Limit number of enrichment URLs
    enrich_urls = enrich_urls[:MAX_ENRICH_URLS]
    
    enriched_data = {}
    
    for idx, url in enumerate(enrich_urls):
        try:
            # Parse and validate URL
            parsed_url = urlparse(url)
            
            # Security validations
            # 1. Only allow HTTPS
            if parsed_url.scheme != 'https':
                enriched_data[f'enrich_{idx}'] = {'error': 'Only HTTPS URLs are allowed'}
                continue
            
            # 2. Validate domain is in allowlist
            hostname = parsed_url.hostname
            if not hostname or hostname not in ALLOWED_DOMAINS:
                enriched_data[f'enrich_{idx}'] = {'error': 'Domain not in allowlist'}
                continue
            
            # 3. Prevent access to private IP ranges
            if is_private_ip(hostname):
                enriched_data[f'enrich_{idx}'] = {'error': 'Private IP addresses not allowed'}
                continue
            
            # 4. Validate port (only standard HTTPS port)
            if parsed_url.port and parsed_url.port != 443:
                enriched_data[f'enrich_{idx}'] = {'error': 'Only standard HTTPS port allowed'}
                continue
            
            # Make HTTP request with security controls
            req = urllib.request.Request(
                url,
                headers={
                    'User-Agent': 'Lambda-Edge-Enrichment/1.0',
                    'Accept': 'application/json'
                }
            )
            
            # Set timeout and size limits
            with urllib.request.urlopen(req, timeout=REQUEST_TIMEOUT) as response:
                # Check content length
                content_length = response.headers.get('Content-Length')
                if content_length and int(content_length) > MAX_RESPONSE_SIZE:
                    enriched_data[f'enrich_{idx}'] = {'error': 'Response too large'}
                    continue
                
                # Read with size limit
                data = response.read(MAX_RESPONSE_SIZE + 1)
                if len(data) > MAX_RESPONSE_SIZE:
                    enriched_data[f'enrich_{idx}'] = {'error': 'Response exceeds size limit'}
                    continue
                
                # Parse JSON response
                try:
                    json_data = json.loads(data.decode('utf-8'))
                    enriched_data[f'enrich_{idx}'] = json_data
                except json.JSONDecodeError:
                    enriched_data[f'enrich_{idx}'] = {'error': 'Invalid JSON response'}
                    
        except urllib.error.HTTPError as e:
            enriched_data[f'enrich_{idx}'] = {'error': f'HTTP error: {e.code}'}
        except urllib.error.URLError as e:
            enriched_data[f'enrich_{idx}'] = {'error': 'URL error or timeout'}
        except Exception as e:
            enriched_data[f'enrich_{idx}'] = {'error': 'Request failed'}
    
    # Add enriched data to request headers (base64 encoded to handle special characters)
    if enriched_data:
        import base64
        enriched_json = json.dumps(enriched_data)
        # Ensure header value doesn't exceed CloudFront limits (8KB per header)
        if len(enriched_json) <= 8000:
            encoded_data = base64.b64encode(enriched_json.encode('utf-8')).decode('utf-8')
            request['headers']['x-enriched-data'] = [{
                'key': 'X-Enriched-Data',
                'value': encoded_data
            }]
    
    return request


def is_private_ip(hostname):
    """Check if hostname resolves to a private IP address"""
    import socket
    
    try:
        # Resolve hostname to IP
        ip = socket.gethostbyname(hostname)
        
        # Check for private IP ranges
        octets = ip.split('.')
        if len(octets) != 4:
            return True
        
        first_octet = int(octets[0])
        second_octet = int(octets[1])
        
        # Private IP ranges:
        # 10.0.0.0/8
        if first_octet == 10:
            return True
        
        # 172.16.0.0/12
        if first_octet == 172 and 16 <= second_octet <= 31:
            return True
        
        # 192.168.0.0/16
        if first_octet == 192 and second_octet == 168:
            return True
        
        # 127.0.0.0/8 (localhost)
        if first_octet == 127:
            return True
        
        # 169.254.0.0/16 (link-local)
        if first_octet == 169 and second_octet == 254:
            return True
        
        # 0.0.0.0/8
        if first_octet == 0:
            return True
        
        return False
        
    except socket.gaierror:
        # If hostname doesn't resolve, block it
        return True
    except Exception:
        # On any error, treat as private for security
        return True